function boomBrowserFixture() {
  throw new TypeError("browser corpus exploded");
}
async function asyncHop() {
  await Promise.resolve();
  boomBrowserFixture();
}
window.__captureStack = async () => {
  try {
    await asyncHop();
  } catch (error) {
    return error.stack || "";
  }
  return "";
};

